name: Deploy to main

on:
  push:
    branches:
      - main
  workflow_dispatch:

jobs:
  deploy:
    runs-on: [self-hosted, jenkins-server]

    steps:
      - name: Checkout code
        uses: actions/checkout@v4

      - name: Deploy latest code
        run: |
          echo ">>> Switching to project directory"
          cd /home/ubuntu/api_code/onboarding_service_frontend

          echo ">>> Fetching latest code from master branch"
          git pull origin main

          echo ">>> Install dependency"
          npm install --legacy-peer-deps
          CI=false npm run build

          echo ">>> rm from s3"
          aws s3 rm s3://loan.ramfincorp.com --recursive

          echo ">>> upload on s3"
          aws s3 cp dist/ s3://loan.ramfincorp.com/ --recursive

          aws cloudfront create-invalidation --distribution-id E43AFN6BHKN1A --paths "/*" --profile default

          echo ">>> Showing last 10 commits"
          git log -10 --oneline
          echo ">>> Deployment completed successfully!"



name: Deploy to main2

on:
  push:
    branches:
      - main2
  workflow_dispatch:

jobs:
  deploy:
    runs-on: [self-hosted, jenkins-server]

    steps:
      - name: Checkout code
        uses: actions/checkout@v4

      - name: Deploy latest code
        run: |
          echo ">>> Switching to project directory"
          cd /home/ubuntu/api_code/onboarding_service_frontend_hyperverge

          echo ">>> Fetching latest code from master branch"
          git pull origin main2

          echo ">>> Install dependency"
          npm install --legacy-peer-deps
          CI=false npm run build

          echo ">>> rm from s3"
          aws s3 rm s3://onboarding-applyloan.ramfincorp.com/ --recursive

          echo ">>> upload on s3"
          aws s3 cp dist/ s3://onboarding-applyloan.ramfincorp.com/ --recursive

          aws cloudfront create-invalidation --distribution-id EHSJYVGHQ2QBC --paths "/*" --profile default

          echo ">>> Showing last 10 commits"
          git log -10 --oneline
          echo ">>> Deployment completed successfully!"



